import collections
rows=[]
for line in open('data/aka.trn', encoding='utf-8'):
    line=line.rstrip('\n').rstrip('\r')
    if not line: continue
    l,f,ft=line.split('\t')
    rows.append((l,f,ft))
# per featset prefix (mode), then suffix per row = strip prefix then lemma
by=collections.defaultdict(list)
for l,f,ft in rows: by[ft].append((l,f))
# Build: for each row, suffix = f after removing a matching prefix and the lemma.
# We know form=pre+lemma+suf. Enumerate splits where middle==lemma; choose split whose 'pre' has no digits... just take the split maximizing... take the one where lemma is found; if multiple, prefer the one giving shortest suffix that is in {'','e','ee'}? 
lem_suf=collections.defaultdict(collections.Counter)
for l,f,ft in rows:
    # find all occurrences
    best=None
    i=f.find(l)
    while i>=0:
        suf=f[i+len(l):]
        if suf in ('','e','ee'):
            best=suf; 
        i=f.find(l,i+1)
    if best is not None:
        lem_suf[l][best]+=1
# Now which lemmas ever take 'e' vs 'ee' (nonempty)
for l in sorted(lem_suf):
    c={k:v for k,v in lem_suf[l].items() if k}
    if c: 
        endch=l[-1]
        print(repr(l), 'ends',endch, dict(c))
