import time,collections
from pyfoma import FST
from pyfoma.fst import State

rows=[]
for line in open('data/aka.trn',encoding='utf-8'):
    line=line.rstrip('\n').rstrip('\r')
    if not line: continue
    l,f,ft=line.split('\t'); rows.append((l,f,ft))
LAB=set('bfmp')
def align(l,f):
    i=f.find(l)
    while i>=0:
        s=f[i+len(l):]
        if s in ('','e','ee'): return f[:i],s
        i=f.find(l,i+1)
by=collections.defaultdict(list)
for l,f,ft in rows: by[ft].append((l,f))
prefix={}; has_suf={}
lemmas=sorted(set(r[0] for r in rows)); featsets=sorted(set(r[2] for r in rows))
for ft,items in by.items():
    hs=False
    for l,f in items:
        p,s=align(l,f); prefix[(ft,l[0] in LAB)]=p
        if s: hs=True
    has_suf[ft]=hs

fst=FST(); start=fst.initialstate
alpha=set()
def arc(cur,label):
    global fst
    ns=State(); fst.states.add(ns); cur.add_transition(ns,label)
    for s in label:
        if s: alpha.add(s)
    return ns
for ft in featsets:
    tags=['['+x+']' for x in ft.split(';')]
    for l in lemmas:
        cur=start
        for tg in tags: cur=arc(cur,(tg,))
        c0=l[0]
        cur=arc(cur,(c0,''))
        p=prefix[(ft,c0 in LAB)]
        for ch in p: cur=arc(cur,('',ch))
        cur=arc(cur,('',c0))
        for ch in l[1:]: cur=arc(cur,(ch,))
        suf=('e' if l.endswith('e') else 'ee') if has_suf[ft] else ''
        for ch in suf: cur=arc(cur,('',ch))
        fst.finalstates.add(cur); cur.finalweight=0.0
fst.alphabet=alpha
print('raw states',len(fst.states),'alpha',len(alpha))
t0=time.time()
fst=fst.epsilon_remove().determinize_as_dfa().minimize()
fst.alphabet=alpha
print('min states',len(fst.states),'time',round(time.time()-t0,1))

def apply_in(l,ft):
    return ['['+x+']' for x in ft.split(';')]+list(l)
ok=0;bad=0
